import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Login() {
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState("");
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const res = await axios.post("http://localhost:8000/login", new URLSearchParams({
                username,
                password
            }));
            localStorage.setItem("token", res.data.access_token);
            localStorage.setItem("role", res.data.role);
            navigate("/dashboard");
        } catch (err) {
            setError("Invalid username or password");
        }
    };

    return (
        <div className="d-flex justify-content-center align-items-center vh-100 bg-light">
            <div className="card shadow-lg border-0 rounded-4 p-4" style={{ maxWidth: "420px", width: "100%" }}>
                <div className="text-center mb-4">
                    <div className="rounded-circle bg-primary text-white d-inline-flex align-items-center justify-content-center shadow-sm" style={{ width: "60px", height: "60px" }}>
                        <i className="bi bi-person-lock fs-3"></i>
                    </div>
                    <h3 className="mt-3 fw-bold">Welcome Back</h3>
                    <p className="text-muted small">Sign in to continue to your dashboard</p>
                </div>

                {error && <div className="alert alert-danger py-2">{error}</div>}

                <form onSubmit={handleSubmit}>
                    <div className="mb-3">
                        <label className="form-label fw-semibold">Username</label>
                        <div className="input-group">
                            <span className="input-group-text bg-light"><i className="bi bi-person"></i></span>
                            <input
                                type="text"
                                className="form-control"
                                placeholder="Enter username"
                                value={username}
                                onChange={(e) => setUsername(e.target.value)}
                                required
                            />
                        </div>
                    </div>

                    <div className="mb-3">
                        <label className="form-label fw-semibold">Password</label>
                        <div className="input-group">
                            <span className="input-group-text bg-light"><i className="bi bi-lock"></i></span>
                            <input
                                type="password"
                                className="form-control"
                                placeholder="Enter password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                            />
                        </div>
                    </div>

                    <button type="submit" className="btn btn-primary w-100 shadow-sm fw-semibold">
                        <i className="bi bi-box-arrow-in-right me-2"></i> Login
                    </button>
                </form>

                <div className="text-center mt-3">
                    <a href="#" className="text-decoration-none small text-primary">Forgot Password?</a>
                </div>
            </div>
        </div>
    );
}

export default Login;
